import { useEffect, useState } from "react";
import { useNavigate, useParams } from "react-router-dom";
import api from "../../api/axios";
import { updateDoc } from "../../api/documentApi";

export default function EditDocument() {
  const { id } = useParams();
  const navigate = useNavigate();

  const [vehicles, setVehicles] = useState([]);
  const [form, setForm] = useState(null);

  const [loading, setLoading] = useState(true);
  const [loadError, setLoadError] = useState("");

  const getVehicleNumber = (v) =>
    v?.vehicleNumber || v?.vehicle_number || v?.registrationNo || v?.regNo || "";

  useEffect(() => {
    const load = async () => {
      setLoading(true);
      setLoadError("");

      try {
        const [docRes, vehicleRes] = await Promise.all([
          api.get(`/documents/${id}`),
          api.get("/vehicles"),
        ]);

        const d = docRes.data;

        setForm({
          title: d.title || "",
          docType: d.docType || "RC_BOOK",
          referenceNo: d.referenceNo || "",
          vehicle: d.vehicle?._id || "",
          status: d.status || "AVAILABLE",
          location: d.location || "",
          notes: d.notes || "",
        });

        setVehicles(vehicleRes.data || []);
      } catch (err) {
        const status = err.response?.status;
        const msg = err.response?.data?.message || err.message;
        setLoadError(`Failed to load document. (${status || "no status"}) ${msg}`);
      } finally {
        setLoading(false);
      }
    };

    load();
  }, [id]);

  const submit = async (e) => {
    e.preventDefault();

    try {
      await updateDoc(id, {
        ...form,
        vehicle: form.vehicle || undefined,
      });

      alert("Document updated!");
      navigate("/documents");
    } catch (err) {
      alert(err.response?.data?.message || "Update failed");
    }
  };

  if (loading) return <p style={{ padding: 20 }}>Loading...</p>;

  if (loadError) {
    return (
      <div style={{ padding: 20 }}>
        <h2>Edit Physical Document</h2>
        <p style={{ color: "red" }}>{loadError}</p>
        <button onClick={() => navigate("/documents")}>Back</button>
      </div>
    );
  }

  if (!form) return <div className="card cardPad" style={{ margin: "20px" }}>No data</div>;

  return (
    <div className="page">
      <div className="pageHead">
        <div>
          <div className="pageTitle">Edit Physical Document</div>
          <div className="pageSub">Update document details and information</div>
        </div>
      </div>

      <div className="card cardPad" style={{ maxWidth: 720, margin: "32px auto" }}>
        <form onSubmit={submit}>
          <label className="label">Title</label>
          <input
            value={form.title}
            onChange={(e) => setForm({ ...form, title: e.target.value })}
            className="input"
            required
          />

          <label className="label" style={{ marginTop: 20 }}>Type</label>
          <select
            value={form.docType}
            onChange={(e) => setForm({ ...form, docType: e.target.value })}
            className="select"
          >
            <option value="RC_BOOK">RC Book</option>
            <option value="INSURANCE">Insurance</option>
            <option value="TRANSFER_FORM">Transfer Form</option>
            <option value="EMISSION">Emission</option>
            <option value="SERVICE_BOOK">Service Book</option>
            <option value="OTHER">Other</option>
          </select>

          <label className="label" style={{ marginTop: 20 }}>Reference No</label>
          <input
            value={form.referenceNo}
            onChange={(e) => setForm({ ...form, referenceNo: e.target.value })}
            className="input"
          />

          <label className="label" style={{ marginTop: 20 }}>Vehicle (shows vehicle number)</label>
          <select
            value={form.vehicle}
            onChange={(e) => setForm({ ...form, vehicle: e.target.value })}
            className="select"
          >
            <option value="">-- none --</option>
            {vehicles.map((v) => {
              const vNum = getVehicleNumber(v);
              return (
                <option key={v._id} value={v._id}>
                  {v.brand} {v.type || ""} ({v.year}){vNum ? ` - ${vNum}` : ""}
                </option>
              );
            })}
          </select>

          <label className="label" style={{ marginTop: 20 }}>Status</label>
          <select
            value={form.status}
            onChange={(e) => setForm({ ...form, status: e.target.value })}
            className="select"
          >
            <option value="AVAILABLE">AVAILABLE</option>
            <option value="IN_USE">IN_USE</option>
            <option value="MISSING">MISSING</option>
            <option value="ARCHIVED">ARCHIVED</option>
          </select>

          <label className="label" style={{ marginTop: 20 }}>Location</label>
          <input
            value={form.location}
            onChange={(e) => setForm({ ...form, location: e.target.value })}
            className="input"
            required
          />

          <label className="label" style={{ marginTop: 20 }}>Note</label>
          <textarea
            value={form.notes}
            onChange={(e) => setForm({ ...form, notes: e.target.value })}
            rows={3}
            className="textarea"
          />

          <div style={{ marginTop: 28, display: "flex", gap: 12 }}>
            <button type="submit" className="btn btnPrimary">Save Changes</button>
            <button type="button" onClick={() => navigate("/documents")} className="btn">Cancel</button>
          </div>
        </form>
      </div>
    </div>
  );
}
